import api from './api';
export default {
  async getAll() {
    const response = await api.request('list', 'ProductRentalAvailability', {});
    return response.data || [];
  },
  async getByProductId(productId) {
    const response = await api.request('getByProduct', 'ProductRentalAvailability', {
      productId
    });
    return response.data;
  },
  async create(productData) {
    const response = await api.request('save', 'ProductRentalAvailability', productData);
    return response.data;
  },
  async update(id, updates) {
    const response = await api.request('update', 'ProductRentalAvailability', {
      id,
      ...updates
    });
    return response.data;
  },
  async delete(id) {
    await api.request('delete', 'ProductRentalAvailability', {
      id
    });
  }
};
